long long contest(string a, string b){
    int i=0;
    int j=0;

    map<char,int> m;
    for(int i=0;i<a.size();i++){
        m[a[i]]++;
    }

    for(auto it: b){
        if(m.find(it)==m.end()) return -1;
    }

    long long ans=0;
    while(j!=b.size()){
        if(a[i]==b[j]){
            j++;
        }
        i=(i+1)%a.size();
        ans++;
    }
    return ans;
}
